#!/usr/bin/env python3
"""NO MUTE 썸네일 오버레이 생성기 - Logo.png 단일 파일 버전"""
import sys, os, re, glob, subprocess
import numpy as np
from PIL import Image, ImageDraw, ImageFont, ImageFilter


SEARCH_DIRS = [
    "/mnt/user-data/uploads/",
    "/mnt/project/",
]


def find_file(pattern):
    for base in SEARCH_DIRS:
        if not os.path.isdir(base):
            continue
        exact = os.path.join(base, pattern)
        if os.path.exists(exact):
            return exact
        matches = glob.glob(os.path.join(base, f"*{pattern}*"))
        if matches:
            return matches[0]
    dirs = []
    for base in SEARCH_DIRS:
        if os.path.isdir(base):
            dirs.extend(os.listdir(base))
    print(f"WARN: '{pattern}' not found in {dirs}")
    return None


def find_font():
    for f in ["/usr/share/fonts/opentype/noto/NotoSansCJK-Bold.ttc",
              "/usr/share/fonts/truetype/noto/NotoSansCJK-Bold.ttc",
              "/usr/share/fonts/noto-cjk/NotoSansCJK-Bold.ttc"]:
        if os.path.exists(f): return f
    r = subprocess.run(["find","/usr/share/fonts","-name","*NotoSans*CJK*Bold*"],capture_output=True,text=True)
    if r.stdout.strip(): return r.stdout.strip().split('\n')[0]
    return None


FONT_PATH = find_font()
assert FONT_PATH, "Font not found!"


SPECS = {
    "reels": {"w":1080,"h":1920,"fs":78,"lh":96,"tr":-1,"lm":101,"ty":1119,
        "logo_rect":(104, 1008, 139, 102),    # x, y, w, h
        "stroke":False,
        "grad":{0:255,5:255,10:255,15:255,20:255,25:255,30:252,33:248,35:243,38:234,
            40:226,43:212,45:200,48:181,50:168,53:151,55:141,58:130,60:123,63:117,65:112,
            68:109,70:107,75:106,80:106,85:106,90:106,95:106,100:106}},
    "post": {"w":1080,"h":1350,"fs":76,"lh":89,"tr":0,"lm":85,"ty":822,
        "logo_rect":(98, 720, 127, 93),   # x, y, w, h
        "stroke":False,
        "grad":{0:255,5:255,10:255,14:252,19:249,21:248,24:245,25:242,27:239,28:236,
            30:234,32:229,33:226,35:222,40:206,45:186,50:169,55:151,60:134,65:121,70:110,
            75:103,80:99,85:95,90:92,95:91,100:91}}
}


SA = int(255*0.8)

# 2K 렌더: 모든 좌표/폰트 = 1080 기준 SPECS × SCALE (SPECS는 1080 유지 → 워크플로 fit_tracking 자간계산 호환).
# 1=레거시 1080 · 2=2160폭(포스트 2160×2700·릴스 2160×3840). 자간(tr)은 em-상대라 스케일 무관.
SCALE = 2


def mk_grad(W,H,gd):
    g=np.zeros((H,W,4),dtype=np.uint8)
    ap={k:255-v for k,v in gd.items()}; sp=sorted(ap.keys())
    for y in range(H):
        p=(y/H)*100; lp=up=0
        for pp in sp:
            if pp<=p: lp=pp
            if pp>=p: up=pp; break
        a=ap[lp] if lp==up else ap[lp]+(p-lp)/(up-lp)*(ap[up]-ap[lp])
        g[y,:,3]=int(min(255,max(0,a)))
    return Image.fromarray(g,'RGBA')


# Logo embedded as base64 (RGBA PNG, 900x664)
import base64, io as _io
_LOGO_B64 = ""


def mk_logo(W, H, logo_rect):
    lx, ly, lw, lh = logo_rect
    src = Image.open(_io.BytesIO(base64.b64decode(_LOGO_B64))).convert('RGBA')
    src = src.resize((lw, lh), Image.LANCZOS)
    canvas = Image.new('RGBA', (W, H), (0, 0, 0, 0))
    canvas.paste(src, (lx, ly), src)
    return canvas


def draw_t(d,x,y,t,f,c,tp,us):
    cx=x
    for ch in t:
        if us:
            sc=(255,255,255,SA) if c==(255,255,255) else (15,253,2,SA)
            d.text((cx,y),ch,font=f,fill=c,stroke_width=1,stroke_fill=sc)
        else:
            d.text((cx,y),ch,font=f,fill=c)
        bb=f.getbbox(ch); cx+=bb[2]-bb[0]+tp
    return cx


def parse(t):
    # 강조 파서(운영자 260720): 별표 run 1~2개 = 강조 델리미터(토글) · 3개 이상 연속 = 리터럴(글자 그대로 = 마스킹 010-****·@id*** 보존).
    # "강조는 안에 글자가 들어가는 것" — 3+ 반복은 마커가 아니라 콘텐츠. 프론트 normEmph2 + 미리보기 renderEmph2와 로직 동일(정본 3면 일치). 'h'=강조(초록)·'n'=일반(흰).
    sg=[]; on=False; buf=''
    i=0; n=len(t)
    while i<n:
        if t[i]=='*':
            j=i
            while j<n and t[j]=='*': j+=1
            if j-i>=3: buf+=t[i:j]                                  # 3+ = 리터럴
            else:
                if buf: sg.append(('h' if on else 'n', buf)); buf=''  # 1~2 = 델리미터 토글
                on=not on
            i=j
        else:
            buf+=t[i]; i+=1
    if buf: sg.append(('h' if on else 'n', buf))
    return sg


def mk_shadow(cl,s_=1):
    a=np.array(cl); s=Image.new('RGBA',cl.size,(0,0,0,0))
    sa=np.array(s);sa[:,:,3]=a[:,:,3];s=Image.fromarray(sa,'RGBA')
    o=Image.new('RGBA',cl.size,(0,0,0,0));o.paste(s,(1*s_,2*s_))
    r,g,b,aa=o.split();aa=aa.filter(ImageFilter.GaussianBlur(radius=2*s_))
    o=Image.merge('RGBA',(r,g,b,aa))
    f=np.array(o);f[:,:,3]=(f[:,:,3].astype(float)*int(255*0.70)/255).astype(np.uint8)
    return Image.fromarray(f,'RGBA')


def generate(fmt, lines, out, opacity=None, tracking=None, lm_offsets=None):
    sp=SPECS[fmt]; S=SCALE
    W=sp["w"]*S; H=sp["h"]*S
    fs=sp["fs"]*S
    fnt=ImageFont.truetype(FONT_PATH,fs,index=1)
    tr_val=tracking if tracking is not None else sp["tr"]   # 자간 = em-상대(1/1000) → 스케일 무관
    tp=tr_val/1000*fs
    c=Image.new('RGBA',(W,H),(0,0,0,0))
    gd=dict(sp["grad"])
    if opacity is not None:
        op=max(0,min(100,opacity))
        max_a=255-min(gd.values())     # 현재 최대 알파
        if max_a>0:
            scale=(op/100*255)/max_a
            gd={k:max(0,min(255,255-int((255-v)*scale))) for k,v in gd.items()}
    c=Image.alpha_composite(c,mk_grad(W,H,gd))
    ll=mk_logo(W, H, tuple(v*S for v in sp["logo_rect"]))
    tx=Image.new('RGBA',(W,H),(0,0,0,0))
    dr=ImageDraw.Draw(tx); cy=sp["ty"]*S
    for i,ln in enumerate(lines):
        cx=sp["lm"]*S+(lm_offsets[i]*S if lm_offsets and i<len(lm_offsets) else 0)
        for st,stx in parse(ln):
            co=(15,253,2) if st=='h' else (255,255,255)
            cx=draw_t(dr,cx,cy,stx,fnt,co,tp,sp["stroke"])
        cy+=sp["lh"]*S
    cb=Image.alpha_composite(ll,tx)
    sh=mk_shadow(cb,S)
    c=Image.alpha_composite(c,sh)
    c=Image.alpha_composite(c,ll)
    c=Image.alpha_composite(c,tx)
    assert c.mode=='RGBA',f"MODE ERROR: {c.mode}"
    c.save(out,format='PNG')
    v=Image.open(out)
    assert v.mode=='RGBA',f"SAVE ERROR: {v.mode}"
    a=np.array(v)[:,:,3]
    print(f"OK: {out} ({v.size},{v.mode}) top_a={a[10,W//2]} bot_a={a[H-10,W//2]}")


if __name__=="__main__":
    if len(sys.argv)<4:
        print("Usage: python3 nomute_overlay.py [reels|post] output.png [--opacity N] [--tracking N] line1 line2 ...")
        sys.exit(1)
    fmt=sys.argv[1]
    out=sys.argv[2]
    opacity=None
    tracking=None
    rest=sys.argv[3:]
    while rest and rest[0].startswith("--"):
        if rest[0]=="--opacity":
            opacity=int(rest[1]); rest=rest[2:]
        elif rest[0]=="--tracking":
            tracking=int(rest[1]); rest=rest[2:]
        else:
            break
    lines=rest
    generate(fmt, lines, out, opacity, tracking)
